----------------------------- */
const messages = ref([])

/* -----------------------------
   COMPUTED
----------------------------- */
const activeMessages = () =>
  messages.value.filter(m => m.chatId === activeChatId.id)
 

/* -----------------------------
   METHODS
----------------------------- */
  async function openChat(chatId) {
    
    activeChatId.id = chatId.other_user_id
    activeChatId.name = chatId.chat_user_name 
 
    const response = await fetch(`/chat/${chatId.other_user_id}`,{
      method: 'GET',
      headers: {
        'Content-Type': 'application/json'
      }
    });

    const data = await response.json();
    messages.value = data.messages
  
    console.log(messages.value);

  }
/***********************SEND MESSAGE******************/
function sendMessage() {
  if (!newMessage.value) return

  messages.value.push({
    from_id: authId,
    to_id: activeChatId.id,
    chatId: activeChatId.id,
    text: newMessage.value,
    me: true,
    avatar: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSOH2aZnIHWjMQj2lQUOWIL2f4Hljgab0ecZQ&s",
  })
   
  console.log(messages.value)

  router.post(`/chat/${activeChatId.id}`,{
    to_id: activeChatId.id,
    text: newMessage.value
  })

  // atualiza última mensagem da sidebar
  // const chat = chat.value.find(c => c.id === activeChatId.id)
  // if (chat) {
  //   chat.lastMessage = newMessage.value
  //   chat.lastMessageAt = "agora"
  // }

  newMessage.value = ""; 
}

onMounted(() => {
    // Escuta o canal privado do chat ativo
    window.Echo.private(`chat.${activeChatId.id}`)
      .listen('MessageSent', (e) => {
        // e.message vem do broadcastWith()
        const chatIndex = chats.value.findIndex(c => c.id === activeChatId.id);

        if (chatIndex !== -1) {
            // Atualiza última mensagem e adiciona vista/novidade
            chats.value[chatIndex].lastMessage = e.message;
            chats.value[chatIndex].lastMessageAt = new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
            chats.value[chatIndex].viewed = false;

            // Opcional: se você tiver um array de mensagens, pode push nele
            // messages.value.push(e.message);
        }
